module RefModule(
    input [3:0] data_in,
    output reg [2:0] data_out
);

reg [2:0] obf_memory [15:0];

initial begin
    obf_memory[0] = 3'b011;
    obf_memory[1] = 3'b000;
    obf_memory[2] = 3'b101;
    obf_memory[3] = 3'b010;
    obf_memory[4] = 3'b111;
    obf_memory[5] = 3'b001;
    obf_memory[6] = 3'b100;
    obf_memory[7] = 3'b110;
    obf_memory[8] = 3'b010;
    obf_memory[9] = 3'b100;
    obf_memory[10] = 3'b001;
    obf_memory[11] = 3'b111;
    obf_memory[12] = 3'b110;
    obf_memory[13] = 3'b011;
    obf_memory[14] = 3'b000;
    obf_memory[15] = 3'b101;
end

always @(*) begin
    data_out = obf_memory[data_in];
end

endmodule
